#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int n;
    scanf("%d", &n);
    int board[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &board[i]);
    }
    qsort(board, n, sizeof(int), compare);
    int b = 0, w = 0;
    for (int i = 0; i < n/2; i++) {
        b += abs(board[n-i-1] - (n-i*2));
        w += abs(board[n-i-1] - (n-1-i*2));
    }
    printf("%d\n", b < w ? b : w);
    return 0;
}
